"  const [silentMode, setSilentMode] = useState<boolean>(() => {
    const saved = localStorage.getItem('auto_video_silent_mode');
    return saved !== null ? saved === 'true' : true; // Default to true as per spec
  });
  useEffect(() => {
    localStorage.setItem('auto_video_silent_mode', String(silentMode));
  }, [silentMode]);

  const [silentDuration, setSilentDuration] = useState<number>(() => {
    const saved = localStorage.getItem('auto_video_silent_duration');
    return saved ? Number(saved) : 10;
  });
  useEffect(() => {
    localStorage.setItem('auto_video_silent_duration', String(silentDuration));
  }, [silentDuration]);"
